namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and rhetoric." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and human civilization." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor", Bio = "Dr. Chen specializes in distributed systems and has published over 50 papers on cloud computing architectures.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Miller", Title = "Associate Professor", Bio = "Dr. Miller focuses on abstract algebra and number theory, with a passion for making advanced mathematics accessible.", Email = "j.miller@university.edu" },
            new() { Id = 3, Name = "Prof. Emily Ward", Title = "Professor", Bio = "Prof. Ward is an award-winning author and literary critic with expertise in modern American fiction.", Email = "e.ward@university.edu" },
            new() { Id = 4, Name = "Dr. Robert Kim", Title = "Assistant Professor", Bio = "Dr. Kim researches quantum mechanics and teaches introductory and advanced physics courses.", Email = "r.kim@university.edu" },
            new() { Id = 5, Name = "Dr. Maria Lopez", Title = "Professor", Bio = "Dr. Lopez is a historian of Latin American studies and recipient of multiple research grants.", Email = "m.lopez@university.edu" },
            new() { Id = 6, Name = "Dr. Alan Turing Jr.", Title = "Associate Professor", Bio = "Dr. Turing specializes in artificial intelligence and machine learning, continuing a family legacy in computing.", Email = "a.turing@university.edu" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00â€“9:50 AM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 2, CourseCode = "CS 301", Title = "Data Structures & Algorithms", Description = "Advanced study of data structures including trees, graphs, and hash tables. Covers algorithm design and complexity analysis.", Credits = 4, Schedule = "Tue/Thu 10:30 AMâ€“12:00 PM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0] },
            new() { Id = 3, CourseCode = "CS 450", Title = "Machine Learning", Description = "Introduction to machine learning concepts including supervised learning, neural networks, and model evaluation techniques.", Credits = 3, Schedule = "Mon/Wed 2:00â€“3:30 PM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[5], IsFeatured = true },
            new() { Id = 4, CourseCode = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, and eigenvalues with applications to science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00â€“11:50 AM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1] },
            new() { Id = 5, CourseCode = "MATH 301", Title = "Abstract Algebra", Description = "Introduction to groups, rings, and fields. Explores algebraic structures and their properties.", Credits = 3, Schedule = "Tue/Thu 1:00â€“2:30 PM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1] },
            new() { Id = 6, CourseCode = "ENG 110", Title = "College Writing", Description = "Develop strong academic writing skills through essay composition, peer review, and revision strategies.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00â€“10:50 AM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2], IsFeatured = true },
            new() { Id = 7, CourseCode = "ENG 350", Title = "American Novel", Description = "Survey of the American novel from the 19th century to present, examining themes of identity, race, and society.", Credits = 3, Schedule = "Tue/Thu 3:00â€“4:30 PM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2] },
            new() { Id = 8, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Introductory mechanics covering kinematics, Newton's laws, energy, momentum, and rotational motion.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00â€“1:50 PM, Lab: Thu 2:00â€“4:00 PM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3] },
            new() { Id = 9, CourseCode = "PHYS 401", Title = "Quantum Mechanics", Description = "Foundational quantum theory: wave functions, SchrĂ¶dinger equation, angular momentum, and hydrogen atom.", Credits = 3, Schedule = "Tue/Thu 9:00â€“10:30 AM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = true },
            new() { Id = 10, CourseCode = "HIST 220", Title = "Modern World History", Description = "Examination of major global events from the 18th century to present, including revolutions, wars, and social movements.", Credits = 3, Schedule = "Mon/Wed 3:00â€“4:30 PM", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[4] },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

