@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Courses - University Course Catalog</PageTitle>

<div class="container py-4">
    <h1 class="mb-4">Course Catalog</h1>

    <form method="get" class="row g-3 mb-4">
        <div class="col-md-6">
            <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
        </div>
        <div class="col-md-4">
            <select name="departmentId" class="form-select">
                <option value="">All Departments</option>
                @foreach (var dept in _departments)
                {
                    <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button type="submit" class="btn btn-primary w-100">Filter</button>
        </div>
    </form>

    @if (_courses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover">
                <thead class="table-light">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Schedule</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in _courses)
                    {
                        <tr>
                            <td><strong>@course.CourseCode</strong></td>
                            <td>@course.Title</td>
                            <td>@course.Department.Name</td>
                            <td>@course.Credits</td>
                            <td class="small">@course.Schedule</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> _courses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _departments = Catalog.GetDepartments();
        _courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

