@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<div class="container py-4">
    <h1 class="mb-4">Enrollment Request</h1>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Your enrollment request has been received. You will be notified once it has been processed.</p>
            <hr />
            <a href="/courses" class="btn btn-outline-success">Browse More Courses</a>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-lg-8">
                @if (_error)
                {
                    <div class="alert alert-danger">Please fill in all required fields.</div>
                }

                <form method="post" @formname="enrollment">
                    <AntiforgeryToken />

                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                        <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                        <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" placeholder="e.g., STU-12345" required />
                    </div>

                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                        <select id="courseId" name="Model.CourseId" class="form-select" required>
                            <option value="0">-- Select a course --</option>
                            @foreach (var course in _courses)
                            {
                                <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode - @course.Title</option>
                            }
                        </select>
                    </div>

                    <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                    <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                </form>
            </div>
        </div>
    }
</div>

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [CascadingParameter] public HttpContext? HttpContext { get; set; }

    private List<Course> _courses = new();
    private bool _submitted;
    private bool _error;

    protected override void OnInitialized()
    {
        _courses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }

        if (HttpMethods.IsPost(HttpContext?.Request.Method ?? ""))
        {
            if (Catalog.SubmitEnrollmentRequest(Model))
            {
                _submitted = true;
            }
            else
            {
                _error = true;
            }
        }
    }
}

